import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

function App() {

  const apiUrl = "https://localhost:7059/api";

  const [jobs, setJobs] = useState([]);
  const [applications, setApplications] = useState([]);

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [registerFullName, setRegisterFullName] = useState("");
  const [registerEmail, setRegisterEmail] = useState("");
  const [registerPassword, setRegisterPassword] = useState("");

  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [showApplications, setShowApplications] = useState(false);

  const [showRegister, setShowRegister] = useState(false);

  const [newJob, setNewJob] = useState({
    title: "",
    description: "",
    location: "",
    salary: ""
  });

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {

    try {

      const response =
        await axios.get(`${apiUrl}/Jobs`);

      setJobs(response.data);

    } catch (error) {

      console.error(error);

    }
  };

  const login = async () => {

    try {

      const response = await axios.post(
        `${apiUrl}/Auth/login`,
        {
          email,
          password
        }
      );

      localStorage.setItem(
        "token",
        response.data.token
      );

      setIsLoggedIn(true);

    } catch (error) {

      console.error(error);

      alert("Login failed");
    }
  };

  const register = async () => {

    try {

      await axios.post(
        `${apiUrl}/Auth/register`,
        {
          fullName: registerFullName,
          email: registerEmail,
          password: registerPassword,
          role: "Candidate"
        }
      );

      alert("Registration successful!");

      setShowRegister(false);

    } catch (error) {

      console.error(error.response?.data);

      alert("Registration failed");
    }
  };

  const logout = () => {

    localStorage.removeItem("token");

    setIsLoggedIn(false);

    setShowApplications(false);
  };

  const applyToJob = async (jobId) => {

    try {

      const token =
        localStorage.getItem("token");

      await axios.post(
        `${apiUrl}/Applications`,
        {
          jobId: jobId
        },
        {
          headers: {
            Authorization:
              `Bearer ${token}`
          }
        }
      );

      alert("Application sent!");

      loadApplications();

    } catch (error) {

      console.error(error);

      alert("Could not apply");
    }
  };

  const loadApplications = async () => {

    try {

      const token =
        localStorage.getItem("token");

      const response =
        await axios.get(
          `${apiUrl}/Applications`,
          {
            headers: {
              Authorization:
                `Bearer ${token}`
            }
          }
        );

      setApplications(response.data);

      setShowApplications(true);

    } catch (error) {

      console.error(error);

      alert("Could not load applications");
    }
  };

  const createJob = async () => {

    try {

      const token =
        localStorage.getItem("token");

      await axios.post(
        `${apiUrl}/Jobs`,
        {
          title: newJob.title,
          description: newJob.description,
          location: newJob.location,
          salary: parseInt(newJob.salary)
        },
        {
          headers: {
            Authorization:
              `Bearer ${token}`
          }
        }
      );

      alert("Job created!");

      setNewJob({
        title: "",
        description: "",
        location: "",
        salary: ""
      });

      loadJobs();

    } catch (error) {

      console.error(error);

      alert("Could not create job");
    }
  };

  if (!isLoggedIn) {

    return (

      <div className="min-vh-100 d-flex align-items-center bg-light">

        <div className="container">

          <div className="row justify-content-center">

            <div className="col-md-5">

              <div className="card shadow-lg border-0">

                <div className="card-body p-5">

                  <h1 className="text-center mb-4">
                    Recruitment Platform
                  </h1>

                  {!showRegister ? (

                    <>

                      <h4 className="mb-3">
                        Login
                      </h4>

                      <input
                        type="email"
                        className="form-control mb-3"
                        placeholder="Email"
                        value={email}
                        onChange={(e) =>
                          setEmail(e.target.value)
                        }
                      />

                      <input
                        type="password"
                        className="form-control mb-3"
                        placeholder="Password"
                        value={password}
                        onChange={(e) =>
                          setPassword(e.target.value)
                        }
                      />

                      <button
                        className="btn btn-primary w-100 mb-3"
                        onClick={login}
                      >
                        Login
                      </button>

                      <button
                        className="btn btn-outline-secondary w-100"
                        onClick={() =>
                          setShowRegister(true)
                        }
                      >
                        Create Account
                      </button>

                    </>

                  ) : (

                    <>

                      <h4 className="mb-3">
                        Register
                      </h4>

                      <input
                        type="text"
                        className="form-control mb-3"
                        placeholder="Full Name"
                        value={registerFullName}
                        onChange={(e) =>
                          setRegisterFullName(
                            e.target.value
                          )
                        }
                      />

                      <input
                        type="email"
                        className="form-control mb-3"
                        placeholder="Email"
                        value={registerEmail}
                        onChange={(e) =>
                          setRegisterEmail(
                            e.target.value
                          )
                        }
                      />

                      <input
                        type="password"
                        className="form-control mb-3"
                        placeholder="Password"
                        value={registerPassword}
                        onChange={(e) =>
                          setRegisterPassword(
                            e.target.value
                          )
                        }
                      />

                      <button
                        className="btn btn-success w-100 mb-3"
                        onClick={register}
                      >
                        Register
                      </button>

                      <button
                        className="btn btn-outline-secondary w-100"
                        onClick={() =>
                          setShowRegister(false)
                        }
                      >
                        Back To Login
                      </button>

                    </>
                  )}

                </div>

              </div>

            </div>

          </div>

        </div>

      </div>
    );
  }

  return (

    <div className="bg-light min-vh-100">

      <nav className="navbar navbar-dark bg-dark px-4">

        <span className="navbar-brand">
          Recruitment Platform
        </span>

        <div>

          <button
            className="btn btn-outline-light me-2"
            onClick={loadApplications}
          >
            View Applications
          </button>

          <button
            className="btn btn-danger"
            onClick={logout}
          >
            Logout
          </button>

        </div>

      </nav>

      <div className="container py-5">

        <div className="card shadow-sm border-0 mb-5">

          <div className="card-body">

            <h3 className="mb-4">
              Create New Job
            </h3>

            <div className="row">

              <div className="col-md-3">

                <input
                  type="text"
                  className="form-control"
                  placeholder="Title"
                  value={newJob.title}
                  onChange={(e) =>
                    setNewJob({
                      ...newJob,
                      title: e.target.value
                    })
                  }
                />

              </div>

              <div className="col-md-3">

                <input
                  type="text"
                  className="form-control"
                  placeholder="Description"
                  value={newJob.description}
                  onChange={(e) =>
                    setNewJob({
                      ...newJob,
                      description: e.target.value
                    })
                  }
                />

              </div>

              <div className="col-md-2">

                <input
                  type="text"
                  className="form-control"
                  placeholder="Location"
                  value={newJob.location}
                  onChange={(e) =>
                    setNewJob({
                      ...newJob,
                      location: e.target.value
                    })
                  }
                />

              </div>

              <div className="col-md-2">

                <input
                  type="number"
                  className="form-control"
                  placeholder="Salary"
                  value={newJob.salary}
                  onChange={(e) =>
                    setNewJob({
                      ...newJob,
                      salary: e.target.value
                    })
                  }
                />

              </div>

              <div className="col-md-2">

                <button
                  className="btn btn-primary w-100"
                  onClick={createJob}
                >
                  Add Job
                </button>

              </div>

            </div>

          </div>

        </div>

        {showApplications && (

          <div className="card shadow-sm border-0 mb-5">

            <div className="card-body">

              <h3 className="mb-4">
                Applications
              </h3>

              <table className="table table-striped">

                <thead>

                  <tr>

                    <th>ID</th>
                    <th>Job ID</th>
                    <th>Candidate ID</th>

                  </tr>

                </thead>

                <tbody>

                  {applications.map(app => (

                    <tr key={app.id}>

                      <td>{app.id}</td>
                      <td>{app.jobId}</td>
                      <td>{app.candidateId}</td>

                    </tr>

                  ))}

                </tbody>

              </table>

            </div>

          </div>
        )}

        <div className="row">

          {jobs.map(job => (

            <div
              className="col-md-4 mb-4"
              key={job.id}
            >

              <div className="card h-100 shadow-sm border-0">

                <div className="card-body d-flex flex-column">

                  <h4 className="fw-bold">
                    {job.title}
                  </h4>

                  <p className="text-muted">
                    {job.description}
                  </p>

                  <p>
                    <strong>Location:</strong> {job.location}
                  </p>

                  <p>
                    <strong>Salary:</strong> {job.salary} SEK
                  </p>

                  <button
                    className="btn btn-success mt-auto"
                    onClick={() =>
                      applyToJob(job.id)
                    }
                  >
                    Apply
                  </button>

                </div>

              </div>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

export default App;
